  CAST_TYPE_BOOLEAN = 1
  CAST_TYPE_INTEGER = 2
  CAST_TYPE_NUMBER = 3
  CAST_TYPE_STRING = 4
  CAST_TYPE_UNKNOWN = 5

  def __init__(self, kind=UNKNOWN, data=None, terminal=False, binary=False):
    Expression.__init__(self)
    self._kind = kind
    self._data = data
    self._ast = None
    self._terminal = terminal
    self._binary = binary
    self._cast_type = Expr.CAST_TYPE_UNKNOWN

  @property
  def kind(self):
    return self._kind

  @kind.setter
  def kind(self, value):
    self._kind = value

  @property
  def data(self):
    return self._data

  @data.setter
