    self._cast_type = value

  @property
  def terminal(self):
    return self._terminal

  @terminal.setter
  def terminal(self, value):
    self._terminal = value

  @property
  def binary(self):
    return self._binary

  @binary.setter
  def binary(self, value):
    self._binary = value

  def __ne__(self, obj):
    return True

  def __eq__(self, obj):
    return False

