class Const(Expr):
  """
    Constant expression with best-effort strong typing.
  """
  def __init__(self, data=None):
    Expr.__init__(self, Expr.CONSTANT, data, terminal=True, binary=False)
    self._is_none = False
    self._is_boolean = False
    self._is_integer = False
    self._is_string = False
    self._is_container = False
    self._is_symbol = False

  @property
  def is_none(self):
    return self._is_none

  @is_none.setter
  def is_none(self, value):
    self._is_none = value

  @property
  def is_boolean(self):
    return self._is_boolean

  @is_boolean.setter
  def is_boolean(self, value):
    self._is_boolean = value

  @property
  def boolean_value(self):
    if self.is_boolean:
      return self.data == 'True'
    return None

  @property
  def is_integer(self):
    return self._is_integer

  @is_integer.setter
  def is_integer(self, value):
    self._is_integer = value

  @property
  def integer_value(self):
    if self.is_integer:
      return int(self.data)
    return None

  @property
  def is_string(self):
    return self._is_string

  @is_string.setter
  def is_string(self, value):
    self._is_string = value

  @property
  def string_value(self):
    if self.is_string:
      return self.data
    return None

  @property
  def is_container(self):
    return self._is_container

  @is_container.setter
  def is_container(self, value):
    self._is_container = value

  def container_value(self):
    if self.is_container:
      return self.data
    return None

  @property
  def is_symbol(self):
    return self._is_symbol

  @is_symbol.setter
  def is_symbol(self, value):
    self._is_symbol = value

  @staticmethod
  def fromValue(arg, is_symbol=False):
    c = Const(data=arg)
    if arg is None:
      c.is_none = True
    elif isinstance(arg, basestring):
      c.is_string = True
    elif isinstance(arg, bool):
      c.is_boolean = True
    elif isinstance(arg, int) or isinstance(arg, long):
      c.is_integer = True
    elif isinstance(arg, tuple):
      c.is_container = True

    if is_symbol:
      c.is_symbol = True
    return c

  def __ne__(self, obj):
    return not self == obj

  def __eq__(self, obj):
    return isinstance(obj, Const) and self.data == obj.data

  def __repr__(self):
    if self.is_symbol:
      return 'Symbol(%s)' % repr(self.data)
    return 'Const(%s)' % repr(self.data)
