public class KaleidoscopeTransformation extends TransformTransformation {

    private float angle = 0;

    private float angle2 = 0;

    private float centreX = 0.5f;

    private float centreY = 0.5f;

    private int sides = 3;

    private float radius = 0;

    private float icentreX;

    private float icentreY;

    /**
     * Construct a KaleidoscopeFilter with no distortion.
     */
    public KaleidoscopeTransformation() {
        setEdgeAction(CLAMP);
    }

    /**
     * Set the number of sides of the kaleidoscope.
     * 
     * @param sides the number of sides
     * @min-value 2
     * @see #getSides
     */
    public KaleidoscopeTransformation setSides(int sides) {
        this.sides = sides;
        return this;
    }

    /**
     * Get the number of sides of the kaleidoscope.
     * 
     * @return the number of sides
     * @see #setSides
     */
    public int getSides() {
        return sides;
    }

    /**
     * Set the angle of the kaleidoscope.
     * 
     * @param angle the angle of the kaleidoscope.
     * @angle
     * @see #getAngle
     */
    public KaleidoscopeTransformation setAngle(float angle) {
        this.angle = angle;
        return this;
    }

    /**
     * Get the angle of the kaleidoscope.
     * 
     * @return the angle of the kaleidoscope.
     * @see #setAngle
     */
    public float getAngle() {
        return angle;
    }

    /**
     * Set the secondary angle of the kaleidoscope.
     * 
     * @param angle2 the angle
     * @angle
     * @see #getAngle2
     */
    public KaleidoscopeTransformation setAngle2(float angle2) {
        this.angle2 = angle2;
        return this;
    }

    /**
     * Get the secondary angle of the kaleidoscope.
     * 
     * @return the angle
     * @see #setAngle2
     */
    public float getAngle2() {
        return angle2;
    }

    /**
     * Set the centre of the effect in the X direction as a proportion of the image size.
     * 
     * @param centreX the center
     * @see #getCentreX
     */
    public KaleidoscopeTransformation setCentreX(float centreX) {
        this.centreX = centreX;
        return this;
    }

    /**
     * Get the centre of the effect in the X direction as a proportion of the image size.
     * 
     * @return the center
     * @see #setCentreX
     */
    public float getCentreX() {
        return centreX;
    }

    /**
     * Set the centre of the effect in the Y direction as a proportion of the image size.
     * 
     * @param centreY the center
     * @see #getCentreY
     */
    public KaleidoscopeTransformation setCentreY(float centreY) {
        this.centreY = centreY;
        return this;
    }

    /**
     * Get the centre of the effect in the Y direction as a proportion of the image size.
     * 
     * @return the center
     * @see #setCentreY
     */
    public float getCentreY() {
        return centreY;
    }

    /**
     * Set the centre of the effect as a proportion of the image size.
     * 
     * @param centre the center
     * @see #getCentre
     */
    public KaleidoscopeTransformation setCentre(PointF centre) {
        this.centreX = centre.x;
        this.centreY = centre.y;
        return this;
    }

    /**
     * Get the centre of the effect as a proportion of the image size.
     * 
     * @return the center
     * @see #setCentre
     */
    public PointF getCentre() {
        return new PointF(centreX, centreY);
    }

    /**
     * Set the radius of the effect.
     * 
     * @param radius the radius
     * @min-value 0
     * @see #getRadius
     */
    public KaleidoscopeTransformation setRadius(float radius) {
        this.radius = radius;
        return this;
    }

    /**
     * Get the radius of the effect.
     * 
     * @return the radius
     * @see #setRadius
     */
    public float getRadius() {
        return radius;
    }

    @Override
    public Bitmap transform(Bitmap source) {
        icentreX = source.getWidth() * centreX;
        icentreY = source.getHeight() * centreY;
        return super.transform(source);
    }

    protected void transformInverse(int x, int y, float[] out) {
        double dx = x - icentreX;
        double dy = y - icentreY;
        double r = Math.sqrt(dx * dx + dy * dy);
        double theta = Math.atan2(dy, dx) - angle - angle2;
        theta = ImageMath.triangle((float) (theta / Math.PI * sides * .5));
        if (radius != 0) {
            double c = Math.cos(theta);
            double radiusc = radius / c;
            r = radiusc * ImageMath.triangle((float) (r / radiusc));
        }
        theta += angle;

        out[0] = (float) (icentreX + r * Math.cos(theta));
        out[1] = (float) (icentreY + r * Math.sin(theta));
    }

    public String toString() {
        return "Distort/Kaleidoscope...";
    }

    @Override
    public String key() {
        return KaleidoscopeTransformation.class.getCanonicalName() + "-" + angle + "-" + angle2 + "-" + centreX + "-" + centreY + "-"
                + sides + "-" + radius + "-" + icentreX + "-" + icentreY;
    }

}
picasso-transformations/src/main/java/com/picassotransformations/jhlabs/EmbossTransformation.java
public class EmbossTransformation extends WholeImageTransformation {

    private final static float pixelScale = 255.9f;

    private float azimuth = 135.0f * ImageMath.PI / 180.0f, elevation = 30.0f * ImageMath.PI / 180f;
    private boolean emboss = false;
    private float width45 = 3.0f;

    public EmbossTransformation() {
    }

    public void setAzimuth(float azimuth) {
        this.azimuth = azimuth;
    }

    public float getAzimuth() {
        return azimuth;
    }

    public void setElevation(float elevation) {
        this.elevation = elevation;
    }

    public float getElevation() {
        return elevation;
    }

    public void setBumpHeight(float bumpHeight) {
        this.width45 = 3 * bumpHeight;
    }

    public float getBumpHeight() {
        return width45 / 3;
    }

    public void setEmboss(boolean emboss) {
        this.emboss = emboss;
    }

    public boolean getEmboss() {
        return emboss;
    }

    @Override
    protected int[] filterPixels(int width, int height, int[] inPixels, Rect transformedSpace) {
        int index = 0;
        int[] outPixels = new int[width * height];

        int[] bumpPixels;
        int bumpMapWidth, bumpMapHeight;

        bumpMapWidth = width;
        bumpMapHeight = height;
        bumpPixels = new int[bumpMapWidth * bumpMapHeight];
        for (int i = 0; i < inPixels.length; i++)
            bumpPixels[i] = PixelUtils.brightness(inPixels[i]);

        int Nx, Ny, Nz, Lx, Ly, Lz, Nz2, NzLz, NdotL;
        int shade, background;

        Lx = (int) (Math.cos(azimuth) * Math.cos(elevation) * pixelScale);
        Ly = (int) (Math.sin(azimuth) * Math.cos(elevation) * pixelScale);
        Lz = (int) (Math.sin(elevation) * pixelScale);

        Nz = (int) (6 * 255 / width45);
        Nz2 = Nz * Nz;
        NzLz = Nz * Lz;

        background = Lz;

        int bumpIndex = 0;

        for (int y = 0; y < height; y++, bumpIndex += bumpMapWidth) {
            int s1 = bumpIndex;
            int s2 = s1 + bumpMapWidth;
            int s3 = s2 + bumpMapWidth;

            for (int x = 0; x < width; x++, s1++, s2++, s3++) {
                if (y != 0 && y < height - 2 && x != 0 && x < width - 2) {
                    Nx = bumpPixels[s1 - 1] + bumpPixels[s2 - 1] + bumpPixels[s3 - 1] - bumpPixels[s1 + 1]
                            - bumpPixels[s2 + 1] - bumpPixels[s3 + 1];
                    Ny = bumpPixels[s3 - 1] + bumpPixels[s3] + bumpPixels[s3 + 1] - bumpPixels[s1 - 1] - bumpPixels[s1]
                            - bumpPixels[s1 + 1];

                    if (Nx == 0 && Ny == 0)
                        shade = background;
                    else if ((NdotL = Nx * Lx + Ny * Ly + NzLz) < 0)
                        shade = 0;
                    else
                        shade = (int) (NdotL / Math.sqrt(Nx * Nx + Ny * Ny + Nz2));
                } else
                    shade = background;

                if (emboss) {
                    int rgb = inPixels[index];
                    int a = rgb & 0xff000000;
                    int r = (rgb >> 16) & 0xff;
                    int g = (rgb >> 8) & 0xff;
                    int b = rgb & 0xff;
                    r = (r * shade) >> 8;
                    g = (g * shade) >> 8;
                    b = (b * shade) >> 8;
                    outPixels[index++] = a | (r << 16) | (g << 8) | b;
                } else
                    outPixels[index++] = 0xff000000 | (shade << 16) | (shade << 8) | shade;
            }
        }

        return outPixels;
    }

    public String toString() {
        return "Stylize/Emboss...";
    }

    @Override
    public String key() {
        return EmbossTransformation.class.getCanonicalName() + "-" + pixelScale + "-" + azimuth + "-" + elevation + "-"
                + emboss + "-" + width45;
    }

}
picasso-transformations/src/main/java/com/picassotransformations/renderscript/RSGaussianBlurTransformation.java
public class RSGaussianBlurTransformation implements Transformation {

    private Context mContext;

    private int mRadius;

    /**
     * Constructor.
     * 
     * @param context The context.
     * @param radius The blur radius: (0, 25]
     */
    public RSGaussianBlurTransformation(Context context, int radius) {
        mContext = context;
        mRadius = radius;
    }

    @Override
    public Bitmap transform(Bitmap source) {
        if (Build.VERSION.SDK_INT < 17) {
            return source;
        }

        RenderScript rs = RenderScript.create(mContext);
        Allocation input = Allocation.createFromBitmap(rs, source, Allocation.MipmapControl.MIPMAP_NONE, Allocation.USAGE_SCRIPT);
        Allocation output = Allocation.createTyped(rs, input.getType());
        ScriptIntrinsicBlur script = ScriptIntrinsicBlur.create(rs, Element.U8_4(rs));
        script.setRadius(mRadius);
        script.setInput(input);
        script.forEach(output);
        output.copyTo(source);
        return source;
    }

    @Override
    public String key() {
        return RSGaussianBlurTransformation.class.getCanonicalName() + "-" + mRadius;
    }

}

