		{
			if ( m_SDWarnTimer != null )
				m_SDWarnTimer.Stop();
			m_SDWarnTimer = Timer.DelayCall( TimeSpan.FromMinutes( timeUntilActive.TotalMinutes * 0.9 ), new TimerCallback( WarnSuddenDeath ) );
